const express = require('express');
const rateLimit = require('express-rate-limit');
const helmet = require('helmet');

const app = express();

// Security middleware
app.use(helmet());

// Rate limiting
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // limit each IP to 100 requests per windowMs
  message: {
    error: 'Too many requests from this IP, please try again later.',
    code: 'RATE_LIMIT_EXCEEDED'
  },
  standardHeaders: true, // return rate limit info in the RateLimit-* headers
  legacyHeaders: false, // Disable the X-RateLimit-* headers
});

// Apply rate limiter to all requests
app.use(limiter);

// Parse JSON requests
app.use(express.json({
  limit: '10kb' // Limit request body size
}));

// Timeout for requests
app.use((req, res, next) => {
  req.setTimeout(30000, () => { // 30 second timeout
    res.status(408).json({
      error: 'Request timeout',
      code: 'REQUEST_TIMEOUT'
    });
  });
  next();
});

app.get('/health', (req, res) => {
  // Input validation for query parameters if needed
  const allowedFields = ['verbose', 'includeTimestamp'];
  const invalidParams = Object.keys(req.query).filter(param => !allowedFields.includes(param));

  if (invalidParams.length > 0) {
    return res.status(400).json({
      error: `Invalid query parameter(s): ${invalidParams.join(', ')}`,
      code: 'INVALID_PARAMETERS',
      allowed: allowedFields
    });
  }

  try {
    const response = { status: 'ok', timestamp: new Date().toISOString() };

    // Add optional verbose information
    if (req.query.verbose === 'true') {
      response.service = 'user-service';
      response.version = '1.0.0';
    }

    res.json(response);
  } catch (error) {
    console.error('Health check error:', error);
    res.status(500).json({
      error: 'Internal server error',
      code: 'INTERNAL_ERROR'
    });
  }
});

app.get('/users', (req, res) => {
  try {
    // Input validation - sanitize and validate query parameters
    let limit = 10;
    let offset = 0;

    if (req.query.limit) {
      const parsedLimit = parseInt(req.query.limit, 10);
      if (isNaN(parsedLimit) || parsedLimit < 1 || parsedLimit > 100) {
        return res.status(400).json({
          error: 'Limit must be a number between 1 and 100',
          code: 'INVALID_LIMIT'
        });
      }
      limit = parsedLimit;
    }

    if (req.query.offset) {
      const parsedOffset = parseInt(req.query.offset, 10);
      if (isNaN(parsedOffset) || parsedOffset < 0) {
        return res.status(400).json({
          error: 'Offset must be a non-negative number',
          code: 'INVALID_OFFSET'
        });
      }
      offset = parsedOffset;
    }

    // Simulated users data
    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    // Apply pagination
    const paginatedUsers = users.slice(offset, offset + limit);

    res.json({
      users: paginatedUsers,
      total: users.length,
      limit,
      offset,
      hasNext: offset + limit < users.length
    });
  } catch (error) {
    console.error('Users endpoint error:', error);
    res.status(500).json({
      error: 'Internal server error',
      code: 'INTERNAL_ERROR'
    });
  }
});

// Handle 404 for undefined routes
app.use('*', (req, res) => {
  res.status(404).json({
    error: `Route ${req.method} ${req.originalUrl} not found`,
    code: 'NOT_FOUND'
  });
});

// Global error handler
app.use((error, req, res, next) => {
  console.error('Unhandled error:', error);

  res.status(500).json({
    error: 'Internal server error',
    code: 'INTERNAL_ERROR'
  });
});

// Start server with error handling
const PORT = process.env.PORT || 3000;
const server = app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
  console.log(`Environment: ${process.env.NODE_ENV || 'development'}`);
});

// Handle server startup errors
server.on('error', (error) => {
  console.error('Server error:', error);
  process.exit(1);
});

// Handle graceful shutdown
process.on('SIGTERM', () => {
  console.log('SIGTERM received, shutting down gracefully');
  server.close(() => {
    console.log('Process terminated');
  });
});

process.on('SIGINT', () => {
  console.log('SIGINT received, shutting down gracefully');
  server.close(() => {
    console.log('Process terminated');
  });
});

module.exports = app;

