const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const { body, query, validationResult } = require('express-validator');

const app = express();

// Security middleware
app.use(helmet());
// Prevent XSS attacks
app.use(helmet.xssFilter());
// Hide powered-by Express header
app.use(helmet.hidePoweredBy());

// Limit request body size
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: true, limit: '10kb' }));

// Rate limiting
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // Limit each IP to 100 requests per window
  message: 'Too many requests from this IP, please try again later.',
  headers: true,
});

// Apply rate limit to all requests
app.use(limiter);

// Health check with input validation
app.get('/health', [
  // Validate query parameters if any
  query('detailed').optional().isBoolean().withMessage('Detailed must be a boolean')
], (req, res) => {
  // Check for validation errors
  const errors = validationResult(req);
  if (!errors.isEmpty()) {
    return res.status(400).json({ 
      error: 'Validation failed', 
      details: errors.array() 
    });
  }

  // Basic health response
  const healthResponse = { 
    status: 'ok', 
    timestamp: new Date().toISOString() 
  };

  // Add detailed info if requested
  if (req.query.detailed === 'true') {
    healthResponse.service = 'user-service';
    healthResponse.version = '1.0.0';
  }

  res.json(healthResponse);
});

// Users endpoint with validation and sanitization
app.get('/users', [
  // Validate and sanitize query parameters
n  query('limit').optional().isInt({ min: 1, max: 100 }).withMessage('Limit must be between 1 and 100'),
  query('offset').optional().isInt({ min: 0 }).withMessage('Offset must be zero or positive')
], (req, res) => {
  // Check for validation errors
  const errors = validationResult(req);
  if (!errors.isEmpty()) {
    return res.status(400).json({ 
      error: 'Validation failed', 
      details: errors.array() 
    });
  }

  // Safe default values
  const limit = req.query.limit ? parseInt(req.query.limit) : 10;
  const offset = req.query.offset ? parseInt(req.query.offset) : 0;

  // Mock user data (in real app, this would come from a database)
  const mockUsers = [
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ];

  // Apply pagination
  const paginatedUsers = mockUsers.slice(offset, offset + limit);

  res.json({
    data: paginatedUsers,
    pagination: {
      limit,
      offset,
      total: mockUsers.length,
      hasMore: offset + limit < mockUsers.length
    }
  });
});

// Catch 404 errors
app.use('*', (req, res) => {
  res.status(404).json({
    error: 'Route not found',
    path: req.originalUrl
  });
});

// Error handling middleware
app.use((err, req, res, next) => {
  console.error('Error:', err.stack);

  // Don't leak sensitive error information in production
  const isProduction = process.env.NODE_ENV === 'production';

  res.status(err.status || 500).json({
    error: isProduction ? 'Internal server error' : err.message,
