const express = require('express');
const path = require('path');

// Security configuration
const MAX_REQUEST_BODY_SIZE = '10kb';
const RATE_LIMIT_WINDOW_MS = 15 * 60 * 1000; // 15 minutes
const MAX_REQUESTS_PER_WINDOW = 100; // 100 requests per 15 minutes

const app = express();

// Security middleware implementations

// 1. Limit request size to prevent payload attacks
app.use(express.json({ limit: MAX_REQUEST_BODY_SIZE }));
app.use(express.urlencoded({ extended: true, limit: MAX_REQUEST_BODY_SIZE }));

// 2. Basic rate limiting (simplified version without external dependencies)
const requestRateLimit = new Map();

app.use((req, res, next) => {
  const clientIP = req.ip || req.connection.remoteAddress;
  const now = Date.now();
  const windowStart = now - RATE_LIMIT_WINDOW_MS;

  // Clean old records
  for (const [ip, timestamps] of requestRateLimit) {
    requestRateLimit.set(ip, timestamps.filter(timestamp => timestamp > windowStart));
    if (requestRateLimit.get(ip).length === 0) {
      requestRateLimit.delete(ip);
    }
  }

  // Get client requests in current window
  const clientRequests = requestRateLimit.get(clientIP) || [];

  if (clientRequests.length >= MAX_REQUESTS_PER_WINDOW) {
    return res.status(429).json({
      error: 'Too many requests', 
      message: 'Rate limit exceeded. Please try again later.'
    });
  }

  // Add current request timestamp
  clientRequests.push(now);
  requestRateLimit.set(clientIP, clientRequests);
  next();
});

// 3. Security headers (manually set important ones)
app.use((req, res, next) => {
  // Basic security headers
  res.setHeader('X-Content-Type-Options', 'nosniff');
  res.setHeader('X-Frame-Options', 'DENY');
  res.setHeader('X-XSS-Protection', '1; mode=block');
  res.setHeader('Strict-Transport-Security', 'max-age=31536000; includeSubDomains');

  // Prevent caching of sensitive responses by default
  res.setHeader('Cache-Control', 'no-store, no-cache, must-revalidate, proxy-revalidate');
  res.setHeader('Pragma', 'no-cache');
  res.setHeader('Expires', '0');

  next();
});

// 4. Input validation middleware
const validateUserParams = (req, res, next) => {
  const { id } = req.params;

  // Basic validation for user id
  if (id) {
    const userId = parseInt(id, 10);
    if (isNaN(userId) || userId <= 0) {
      return res.status(400).json({
        error: 'Invalid parameter',
        message: 'User ID must be a positive integer'
      });
    }

    // Additional check for very large numbers
    if (userId > 1000000) {
      return res.status(400).json({
        error: 'Invalid parameter',
        message: 'User ID is too large'
      });
    }

    // Attach validated ID to request
    req.validated = req.validated || {};
    req.validated.userId = userId;
  }

  next();
};

// 5. CORS-like security (simplified)
app.use((req, res, next) => {
  const allowedOrigins = ['http://localhost:3000']; // In production, be more specific
  const origin = req.headers.origin;

  if (allowedOrigins.includes(origin)) {
    res.setHeader('Access-Control-Allow-Origin', origin);
  }

  res.setHeader('Access-Control-Allow-Methods', 'GET, POST, OPTIONS');
  res.setHeader('Access-Control-Allow-Headers', 'Content-Type, Authorization');

  // Handle preflight requests
  if (req.method === 'OPTIONS') {
    return res.status(200).end();
  }

  next();
});

// 6. Error handling middleware
// Catch 404 errors
app.use((req, res, next) => {
  res.status(404).json({
    error: 'Not Found',
    message: `The route ${req.method} ${req.url} does not exist.`
  });
});

// Global error handler
app.use((error, req, res, next) => {
  console.error('Uncaught error:', error);

