// Simple rate limiting object to track IP requests
const rateLimit = {};
const WINDOW_MS = 15 * 60 * 1000; // 15 minutes
const MAX_REQUESTS = 100; // Max requests per window

// Middleware for rate limiting
const rateLimitMiddleware = (req, res, next) => {
  const ip = req.ip || req.connection.remoteAddress;
  const now = Date.now();

  // Clean up old entries
  if (rateLimit[ip]) {
    rateLimit[ip].requests = rateLimit[ip].requests.filter(
      timestamp => timestamp > now - WINDOW_MS
    );
  }

  // Initialize IP entry if needed
  if (!rateLimit[ip]) {
    rateLimit[ip] = { requests: [] };
  }

  // Check if rate limit exceeded
  if (rateLimit[ip].requests.length >= MAX_REQUESTS) {
    return res.status(429).json({ 
      error: 'Too many requests from this IP, please try again later.',
      code: 'RATE_LIMIT_EXCEEDED'
    });
  }

  // Add current request timestamp
  rateLimit[ip].requests.push(now);
  next();
};

// Middleware to set security headers
const securityHeaders = (req, res, next) => {
  res.setHeader('X-Content-Type-Options', 'nosniff');
  res.setHeader('X-Frame-Options', 'DENY');
  res.setHeader('X-XSS-Protection', '1; mode=block');
  res.removeHeader('X-Powered-By'); // Hide Express
  next();
};

// Middleware for input validation
