const express = require('express');
const rateLimit = require('express-rate-limit');
const helmet = require('helmet');
const cors = require('cors');
const xss = require('xss-clean');
const hpp = require('hpp');

const app = express();

// Security middleware
app.use(helmet()); // Set security HTTP headers

// CORS configuration - restrict to known origins in production
app.use(cors({
  origin: process.env.NODE_ENV === 'production' 
    ? ['https://yourdomain.com'] 
    : '*',
}));

// Prevent XSS attacks
app.use(xss());

// Prevent HTTP parameter pollution
app.use(hpp());

// Limit requests from same IP
const limiter = rateLimit({
  max: 100, // limit each IP to 100 requests per windowMs
  windowMs: 15 * 60 * 1000, // 15 minutes
  message: 'Too many requests from this IP, please try again later',
});

app.use('/api', limiter);

// Body parsing with size limits
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: true, limit: '10kb' }));

// Request logging (simplified)
app.use((req, res, next) => {
  console.log(`${new Date().toISOString()} - ${req.method} ${req.path}`);
  next();
});

// Health check with proper error handling
app.get('/health', (req, res) => {
  try {
    // Validate any query parameters if needed
    const allowedFields = ['verbose', 'details'];
    const queryFields = Object.keys(req.query);

    for (const field of queryFields) {
      if (!allowedFields.includes(field)) {
        return res.status(400).json({
          error: 'Invalid query parameter',
          details: `Query parameter '${field}' is not allowed`
        });
      }
    }

    const healthData = {
      status: 'ok',
      timestamp: new Date().toISOString(),
      uptime: process.uptime(),
    };

    // Add verbose info if requested
    if (req.query.verbose === 'true') {
      healthData.environment = process.env.NODE_ENV || 'development';
      healthData.version = process.env.npm_package_version || '1.0.0';
    }

    res.json(healthData);
  } catch (error) {
    console.error('Health check error:', error);
    res.status(500).json({
      error: 'Health check failed',
      timestamp: new Date().toISOString()
    });
  }
});

// Users endpoint with input validation and error handling
app.get('/users', (req, res) => {
  try {
    // Input validation for query parameters
    const { page = 1, limit = 10, sort = 'id' } = req.query;

    // Validate page and limit
    const pageNum = parseInt(page);
    const limitNum = parseInt(limit);

    if (isNaN(pageNum) || pageNum < 1) {
      return res.status(400).json({
        error: 'Invalid page parameter',
        details: 'Page must be a positive integer'
      });
    }

    if (isNaN(limitNum) || limitNum < 1 || limitNum > 100) {
      return res.status(400).json({
        error: 'Invalid limit parameter',
        details: 'Limit must be a positive integer between 1 and 100'
      });
    }

    // Validate sort parameter
    const allowedSortFields = ['id', 'name', 'email'];
    if (!allowedSortFields.includes(sort)) {
      return res.status(400).json({
        error: 'Invalid sort parameter',
        details: `Sort field must be one of: ${allowedSortFields.join(', ')}`
      });
    }

    // Simulated users data
    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    // In a real app, you would implement actual pagination and sorting here
    const sortedUsers = [...users].sort((a, b) => {
      if (sort === 'name') return a.name.localeCompare(b.name);
      if (sort === 'email') return a.email.localeCompare(b.email);
      return a.id - b.id; // default sort by id
    });

    const startIndex = (pageNum - 1) * limitNum;
    const paginatedUsers = sortedUsers.slice(startIndex, startIndex + limitNum);

    res.json({
      data: paginatedUsers,
      pagination: {
        currentPage: pageNum,
        totalPages: Math.ceil(users.length / limitNum),
        totalItems: users.length,
        itemsPerPage: limitNum
      }
    });
  } catch (error) {
    console.error('Users endpoint error:', error);
    res.status(500).json({
      error: 'Internal server error',
      message: 'Failed to retrieve users',
      timestamp: new Date().toISOString()
    });
  }
});

// 404 handler for undefined routes
app.use('*', (req, res) => {
  res.status(404).json({
    error: 'Route not found',
    message: `Cannot ${req.method} ${req.path}`
  });
});

// Global error handler
app.use((error, req, res, next) => {
  console.error('Uncaught error:', error);

  // Never reveal sensitive error information in production
  const isProd = process.env.NODE_ENV === 'production';

  res.status(error.statusCode || 500).json({
    error: isProd ? 'Internal server error' : error.message,
    message: isProd ? 
      'An error occurred' : 
      (error.message || 'Internal server error'),
    timestamp: new Date().toISOString(),
    // Include stack only in development
    ...(isProd ? {} : { stack: error.stack })
  });
});

// Graceful shutdown
process.on('unhandledRejection', (err) => {
  console.error('UNHANDLED REJECTION! 💥 Shutting down...');
  console.error(err);
  process.exit(1);
});

process.on('uncaughtException', (err) => {
  console.error('UNCAUGHT EXCEPTION! 💥 Shutting down...');
  console.error(err);
  process.exit(1);
});

const PORT = process.env.PORT || 3000;
const server = app.listen(PORT, () => {
  console.log(`Server running on port ${PORT} in ${process.env.NODE_ENV || 'development'} mode`);
});

module.exports = app;

