    ];

    // Apply sorting if requested
    let sortedUsers = [...users];
    if (sort) {
      sortedUsers.sort((a, b) => {
        if (a[sort] < b[sort]) return -1;
        if (a[sort] > b[sort]) return 1;
        return 0;
      });
